static void cb_check_basic(void *ctx, int ffd,
                           int res_ret, void *res_data, size_t res_size,
                           void *data)
{
    char *p;
    flb_sds_t out = res_data;
    char *index_line = "key=\"value\"";

    set_output_num(1);

    p = strstr(out, index_line);
    if (!TEST_CHECK(p != NULL)) {
      TEST_MSG("Given:%s", out);
    }

    flb_free(out);
}

